11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_RATE = 0.1;
13	const BASE_PREMIUM: Record<string, number> = { sword: 100, staff: 80, potion: 40, rune: 25 };
14	const DEFAULT_BASE_PREMIUM = 60;
15	
16	const BLOCK_SIZE = 3;
17	const BLOCK_PREMIUM = 60;
18	
19	export function quote(policy: Policy) {
20	  let basePremium = 0;
21	
22	  const counts: Record<string, number> = {};
23	  for (const item of policy.items) {
24	    counts[item.type] = (counts[item.type] ?? 0) + 1;
25	  }
26	
27	  for (const [type, count] of Object.entries(counts)) {
28	    if (count === BLOCK_SIZE) {
29	      basePremium += BLOCK_PREMIUM;
30	    } else {
31	      basePremium += count * (BASE_PREMIUM[type] ?? DEFAULT_BASE_PREMIUM);
32	    }
33	  }
34	
35	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
36	  const premium = Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
37	  return { premium };
38	}
